def probe(path):
    r = subprocess.run(["ffprobe", "-v", "quiet", "-print_format", "json", "-show_streams", path],
                       capture_output=True, text=True)
    vs = [s for s in json.loads(r.stdout)["streams"] if s["codec_type"] == "video"][0]
    return int(vs["width"]), int(vs["height"])
